function deepEqual(a, b) {
  if (a === b) return true;
  if (a == null || b == null || typeof a !== 'object' || typeof b !== 'object') return false;
  const keysA = Object.keys(a), keysB = Object.keys(b);
  if (keysA.length !== keysB.length) return false;
  return keysA.every(key => keysB.includes(key) && deepEqual(a[key], b[key]));
}

Array.prototype.myReduce = function(callback, initialValue) {
  let acc = initialValue;
  let startIndex = 0;
  if (acc === undefined) {
    acc = this[0];
    startIndex = 1;
  }
  for (let i = startIndex; i < this.length; i++) {
    acc = callback(acc, this[i], i, this);
  }
  return acc;
};

function promiseAll(promises) {
  return new Promise((resolve, reject) => {
    const results = [];
    let completed = 0;
    if (promises.length === 0) return resolve([]);
    promises.forEach((p, i) => {
      Promise.resolve(p).then(val => {
        results[i] = val;
        completed++;
        if (completed === promises.length) resolve(results);
      }).catch(reject);
    });
  });
}

async function retry(fn, retries = 3, delay = 1000) {
  for (let i = 0; i <= retries; i++) {
    try {
      return await fn();
    } catch (err) {
      if (i === retries) throw err;
      await new Promise(r => setTimeout(r, delay));
    }
  }
}

class EventBus {
  constructor() { this.events = {}; }
  on(event, callback) {
    (this.events[event] ||= []).push(callback);
  }
  off(event, callback) {
    if (!this.events[event]) return;
    this.events[event] = this.events[event].filter(cb => cb !== callback);
  }
  emit(event, ...args) {
    (this.events[event] || []).forEach(cb => cb(...args));
  }
}

Function.prototype.myBind = function(context, ...boundArgs) {
  const fn = this;
  return function(...args) {
    return fn.apply(context, [...boundArgs, ...args]);
  };
};

class MyPromise {
  constructor(executor) {
    this.state = 'pending';
    this.value = undefined;
    this.callbacks = [];
    const resolve = val => {
      if (this.state !== 'pending') return;
      this.state = 'fulfilled'; this.value = val;
      this.callbacks.forEach(cb => cb.onFulfilled(val));
    };
    const reject = val => {
      if (this.state !== 'pending') return;
      this.state = 'rejected'; this.value = val;
      this.callbacks.forEach(cb => cb.onRejected(val));
    };
    try { executor(resolve, reject); } catch (e) { reject(e); }
  }
  then(onFulfilled, onRejected) {
    return new MyPromise((resolve, reject) => {
      const handle = { onFulfilled: v => { try { resolve(onFulfilled ? onFulfilled(v) : v); } catch(e) { reject(e); } }, onRejected: v => { try { if (onRejected) resolve(onRejected(v)); else reject(v); } catch(e) { reject(e); } } };
      if (this.state === 'pending') this.callbacks.push(handle);
      else if (this.state === 'fulfilled') handle.onFulfilled(this.value);
      else handle.onRejected(this.value);
    });
  }
  catch(onRejected) { return this.then(null, onRejected); }
}

class LazyIterator {
  constructor(data) { this.data = data; this.ops = []; }
  map(fn) { this.ops.push({ type: 'map', fn }); return this; }
  filter(fn) { this.ops.push({ type: 'filter', fn }); return this; }
  take(n) { this.ops.push({ type: 'take', n }); return this; }
  toArray() {
    const result = [];
    let taken = Infinity;
    const takeOp = this.ops.find(o => o.type === 'take');
    if (takeOp) taken = takeOp.n;
    for (const item of this.data) {
      let val = item, skip = false;
      for (const op of this.ops) {
        if (op.type === 'map') val = op.fn(val);
        else if (op.type === 'filter' && !op.fn(val)) { skip = true; break; }
      }
      if (!skip) result.push(val);
      if (result.length >= taken) break;
    }
    return result;
  }
}

function flat(arr, depth = 1) {
  if (depth <= 0) return arr.slice();
  return arr.reduce((acc, val) => {
    if (Array.isArray(val)) acc.push(...flat(val, depth - 1));
    else acc.push(val);
    return acc;
  }, []);
}

function compose(...fns) {
  return function(x) {
    return fns.reduceRight((acc, fn) => fn(acc), x);
  };
}
